window.DAILY_NEWS_ISSUES["2026-06-23"] = {"id": "tech-2026-06-23", "section_slug": "tech", "publication_name": "我的日报·科技", "issue_date": "2026-06-23", "volume": 1, "number": 1, "date_cn": "2026 年 6 月 23 日 · 周二", "output_path": "issues/2026-06-23.html", "headlines": [{"source_item_ids": ["f81dcd58a1bb3db8"], "kicker": "AI Compute", "title_zh": "Reflection AI 向 SpaceX 购买多年 Nvidia GB300 算力", "summary_zh": "Reflection AI 将从 2026 年 7 月 1 日起向 SpaceX 支付每月 1.5 亿美元，使用 SpaceX 位于田纳西州孟菲斯 Colossus 2 数据中心的 Nvidia GB300 芯片和配套硬件，合同延续到 2029 年，最高价值 63 亿美元。", "read_body_zh": ["TechCrunch 报道称，Reflection AI 与 SpaceX 达成算力采购协议。Reflection AI 从 2026 年 7 月 1 日开始获得 SpaceX Colossus 2 数据中心的 Nvidia GB300 AI 芯片和相关硬件访问权，月付 1.5 亿美元，合同期限到 2029 年。", "报道同时提到，SpaceX 还与 Anthropic、Google 有更大规模的算力合同；Reflection AI 这笔交易规模较小，但这是该公司的第一笔算力协议。合同允许任一方在前三个月后提前 90 天通知终止。", "Reflection AI 用这笔交易强调自己的开放权重 AI 路线。报道披露的事实是，开放模型公司同样需要长期、集中、昂贵的数据中心算力供给，且这些供给已经由少数拥有大规模 GPU 集群的公司掌握。"], "pullquote": null, "ai_impact": "这条新闻的关键不只是合同金额，而是算力市场的结构：前沿模型创业公司即便强调开放权重，也绕不开封闭的 GPU 数据中心资源。SpaceX、xAI、云厂商和芯片厂商之间的算力调度，正在变成 AI 公司竞争力的一部分。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/spacex-inks-compute-deal-with-reflection-ai-an-open-source-ai-lab"}], "relevance_score": 98, "importance_score": 95}, {"source_item_ids": ["88b75cef83769816", "c0bfc8ee5e9ad564"], "kicker": "AI Chips", "title_zh": "AI 推理芯片继续融资：凌川量产视频芯片，Groq 转向 neocloud", "summary_zh": "36氪报道，快手系 AI 芯片公司凌川科技完成数亿元 A+ 轮融资，SL200 芯片已销售近十万颗；TechCrunch 报道，Groq 确认完成 6.5 亿美元融资，并在 Nvidia 授权和招揽核心团队后继续招聘、推进 neocloud 业务。", "read_body_zh": ["凌川科技由北京市人工智能基金与快手集团共同发起设立，前身是快手异构计算与芯片事业部。36氪报道，其 SL200 智能视频 SoC 已部署在快手、阿里云、百度云、B 站等互联网公司，覆盖快手 99.7% 的直播转码业务。", "这家公司把重点放在视频生成、多模态大模型和视频处理场景。报道称，其芯片路线包括 DiPU 架构、RISC-V 生态、统一计算平台 LUCAS，以及面向下一代产品的 3D 近存架构。", "美国方向上，Groq 确认完成 6.5 亿美元融资。TechCrunch 报道称，Groq 在 Nvidia 与其签署技术授权协议并招揽创始人 Jonathan Ross 等核心人员之后，继续融资、补充管理层，并把业务重心放在 neocloud。"], "pullquote": null, "ai_impact": "这两条放在一起看，AI 芯片公司的压力已经从“能不能做出芯片”转向“能不能找到稳定场景和商业闭环”。凌川依托视频业务验证成本和效率，Groq 则试图从芯片扩展到云服务。推理侧机会仍在，但纯芯片叙事会越来越难。", "sources": [{"name": "36氪", "url": "https://36kr.com/p/3865136165344516?f=rss"}, {"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/ai-chipmaker-groq-confirms-650m-raise-re-staffs-after-nvidias-20b-not-acqui-hire-deal"}], "relevance_score": 95, "importance_score": 88}, {"source_item_ids": ["b169271bf13b50ce", "e3a98cbb5c7c4389", "ba246d627f29e600"], "kicker": "Data Centers", "title_zh": "AI 数据中心进入资源约束期：Nvidia 谈节水，Microsoft 转向燃气供电", "summary_zh": "Nvidia 宣称 Rubin 代参考数据中心采用全液冷后，可在设施内部显著减少用水；TechCrunch 同时指出，这种口径不覆盖数据中心外部发电带来的水耗。另据报道，Microsoft 与 Chevron 计划在得州建设 2.67GW 天然气电厂，为 AI 和云数据中心供电。", "read_body_zh": ["The Verge 报道称，Nvidia 强调 Rubin 代参考设计会采用 100% 液冷，并在更高运行温度下减少数据中心内部水耗。Nvidia 的说法是，这类设计能在设施内接近消除用水需求。", "TechCrunch 对同一主题补充了边界问题：Nvidia 的统计主要把范围限定在数据中心内部，而 AI 数据中心如果依赖化石燃料电力，发电环节仍可能带来水耗和碳排压力。", "另一条 TechCrunch 报道显示，Microsoft 与 Chevron 计划在得州建设 2.67GW 天然气电厂，向 Microsoft 运营的数据中心供电，协议期限为 20 年。该项目使用 GE Vernova 燃机和 Solar Turbines 设备，被称为美国较大的燃气电力与数据中心共址项目之一。"], "pullquote": null, "ai_impact": "AI 基建正在从“买 GPU”扩展为“抢水、电、土地和电网接入”。液冷能降低设施内部水耗，但不等于解决 AI 的资源账。Microsoft 直接绑定长期燃气供电，说明算力增长已经开始重塑能源采购，而不是只消耗云预算。", "sources": [{"name": "The Verge", "url": "https://www.theverge.com/tech/954139/nvidia-data-centers-rubin-liquid-cooling"}, {"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/nvidia-wants-to-cut-data-center-water-use-but-thats-not-the-same-as-fixing-ais-water-problem"}, {"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/microsoft-and-chevron-plan-one-of-the-largest-gas-powered-data-center-projects-in-us"}], "relevance_score": 92, "importance_score": 86}, {"source_item_ids": ["ae15b112b9f6bdcc", "3a985468823590e8"], "kicker": "Autopilot", "title_zh": "Tesla Autopilot 事故再引调查：公司回应与监管核查并行", "summary_zh": "美国得州一辆 Tesla Model 3 撞入住宅并造成一名 76 岁女性死亡。司机向警方称事故时车辆使用了自动驾驶辅助系统。TechCrunch 报道 Tesla 高管在 X 上反驳外界叙事；Ars Technica 报道称警方和 NHTSA 正在调查 Autopilot 是否相关。", "read_body_zh": ["事故发生在得州 Katy，一辆 Tesla Model 3 离开道路并撞入住宅，屋内 76 岁女性 Martha Avila 后来死亡。TechCrunch 报道称，司机 Michael Butler 告诉警方，车辆当时处于 Autopilot 状态。", "Tesla AI 软件副总裁 Ashok Elluswamy 随后在 X 上回应，试图反驳事故叙事。报道指出，在调查人员完成车辆数据日志分析之前，Autopilot 是否真正启用、是否被覆盖或是否故障仍无法确认。", "Ars Technica 报道称，Harris County 警方确认司机说自己当时使用了自动驾驶辅助系统，警方和 NHTSA 都在调查该系统是否与事故有关。警方也称司机没有醉酒，并正在配合调查。"], "pullquote": null, "ai_impact": "自动驾驶辅助系统的核心风险是公众理解和产品边界之间的落差。即便最终调查认定系统不是直接原因，只要用户认为车辆在“自动驾驶”，事故就会继续转化为监管、品牌和法律压力。Tesla 的技术叙事会越来越依赖可审计的数据日志。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/tesla-pushes-back-on-autopilot-narrative-after-fatal-texas-crash"}, {"name": "Ars Technica", "url": "https://arstechnica.com/tech-policy/2026/06/woman-killed-when-tesla-driver-using-autopilot-crashed-into-her-home"}], "relevance_score": 88, "importance_score": 84}, {"source_item_ids": ["416004de0dc49352", "9b4a6b8f3f3e98df"], "kicker": "AI Security", "title_zh": "OpenAI 把模型能力推向漏洞修复：Patch the Planet 与 GPT-5.5-Cyber 同日出现", "summary_zh": "OpenAI 推出 Patch the Planet 计划，与 Trail of Bits 合作帮助开源维护者发现和修复安全问题；OpenAI Daybreak 页面同时披露 Codex Security 更新、GPT-5.5-Cyber 和网络防御合作计划。", "read_body_zh": ["TechCrunch 报道称，OpenAI 发布 Patch the Planet 计划，将与安全公司 Trail of Bits 合作，为开源维护者审查潜在代码问题，并使用 Codex Security 等工具辅助修复。", "OpenAI 在 Daybreak 页面还提到，相关模型已经用于发现并生成关键漏洞补丁，覆盖浏览器、网络基础设施、FreeBSD 和 Linux kernel 等系统。页面列出的产品包括 Codex Security 更新和 GPT-5.5-Cyber。", "OpenAI 表示，Patch the Planet 的目标是先由安全工程师审查模型发现的问题，再交给维护者，并与项目一起开发补丁和测试。事实层面，这意味着模型被放进了漏洞发现、补丁生成和维护者工作流。"], "pullquote": null, "ai_impact": "AI 安全工具从“帮开发者写代码”走向“主动找漏洞并生成补丁”，会改变开源项目的维护成本结构。但这类能力也需要可信审查链路，否则维护者可能被低质量报告淹没。OpenAI 选择和 Trail of Bits 合作，说明它也意识到纯模型输出还不能直接进入关键安全流程。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/openai-launches-new-initiative-to-help-find-and-patch-open-source-bugs"}, {"name": "OpenAI", "url": "https://openai.com/index/daybreak-securing-the-world"}], "relevance_score": 89, "importance_score": 80}], "briefs": [{"source_item_ids": ["c8289503e0925361"], "title_zh": "Anthropic 的风险叙事被卷入 AI 出口管制争议", "summary_zh": "Ars Technica 援引 FT 分析称，Anthropic 在 2026 年官方表述中更频繁谈到风险、监管和限制；在美国限制外国人访问其新模型后，部分批评者认为该公司的风险叙事加剧了监管后果。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/ai/2026/06/how-anthropic-may-have-talked-itself-into-an-ai-export-ban"}], "relevance_score": 84, "importance_score": 80}, {"source_item_ids": ["d4d27ac0a9ae3181"], "title_zh": "Claude 可能在部分场景要求用户上传身份证件", "summary_zh": "TechCrunch 报道，Anthropic 新版隐私政策写明，Claude 在特定情况下可能要求用户通过护照或驾照等政府证件验证年龄或身份，政策预计 2026 年 7 月 8 日生效。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/anthropic-says-claude-may-want-to-see-your-id"}], "relevance_score": 78, "importance_score": 68}, {"source_item_ids": ["bb590f8e5bb0a781"], "title_zh": "工信部将编制智能网联新能源汽车“十五五”规划", "summary_zh": "36氪援引证券时报消息，工信部装备工业一司负责人表示，将加快编制智能网联新能源汽车产业发展“十五五”规划，并推进新一代动力电池、车用芯片、操作系统、自动驾驶等技术攻关。", "sources": [{"name": "36氪", "url": "https://36kr.com/newsflashes/3865488982578185?f=rss"}], "relevance_score": 82, "importance_score": 72}, {"source_item_ids": ["2d1ab8d865ad790e", "0285851d91c14cbd"], "title_zh": "GLM-5.2 热度上升：本地运行与 Opus 对比同时出圈", "summary_zh": "Unsloth 文档称 GLM-5.2 是 744B 参数、40B 激活参数、1M 上下文窗口的开放模型，并提供本地运行方案；另一篇对比文章用 WebGL 游戏生成测试 GLM-5.2 与 Claude Opus 4.8。", "sources": [{"name": "Hacker News", "url": "https://unsloth.ai/docs/models/glm-5.2"}, {"name": "Hacker News", "url": "https://techstackups.com/comparisons/glm-5.2-vs-opus"}], "relevance_score": 82, "importance_score": 70}, {"source_item_ids": ["1c09d201b7033f3f"], "title_zh": "瑞士 AI Initiative 发布 Apertus 开放基础模型", "summary_zh": "Apertus 项目由 Swiss AI Initiative 推动，强调开放权重、开放数据、开放科学，并声称训练数据、代码、权重、方法和对齐原则均可文档化和复现。", "sources": [{"name": "Hacker News", "url": "https://apertvs.ai"}], "relevance_score": 78, "importance_score": 64}, {"source_item_ids": ["b45d2ed97baf6903"], "title_zh": "AMD 在用户抗议后恢复消费级 CPU 内存加密", "summary_zh": "Ars Technica 报道，AMD 将恢复消费级 Ryzen 处理器的 TSME 内存加密能力。该功能可对内存内容加密，以降低冷启动等需要物理访问的攻击风险。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/security/2026/06/following-user-outcry-amd-reinstates-memory-encryption-in-consumer-cpus"}], "relevance_score": 80, "importance_score": 70}, {"source_item_ids": ["580ed560b721127a"], "title_zh": "Apple 与 Tesla 供应商 Tata Electronics 确认数据泄露", "summary_zh": "TechCrunch 报道，Tata Electronics 确认发生数据泄露。黑客论坛声称拥有超过 630GB 数据，样本中疑似包含 Apple 供应商规格和 Tesla 制造文档。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/tata-electronics-a-major-tech-supplier-to-apple-and-tesla-confirms-data-breach"}], "relevance_score": 70, "importance_score": 65}, {"source_item_ids": ["c05c858300ed3a14"], "title_zh": "安全公司公开 Apple 芯片不可修复漏洞细节", "summary_zh": "TechCrunch 报道，欧洲攻击性安全公司 Paradigm Shift 公开名为 usbliter8 的 Apple 芯片漏洞和概念验证。该漏洞影响旧款 iPhone，需要物理接触目标设备。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/a-new-unpatchable-flaw-in-apple-chips-opens-the-door-to-an-iphone-jailbreak"}], "relevance_score": 72, "importance_score": 66}, {"source_item_ids": ["964451d4f92d3852"], "title_zh": "AI 开发工作流开始讨论“agent loop”", "summary_zh": "TechCrunch 报道，Claude Code 创建者 Boris Cherny 在 Meta @Scale 会议上谈到 loops：agent 不只写代码，还可以持续在后台检查架构、寻找重复抽象并提交 pull request。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/the-ai-world-is-getting-loopy"}], "relevance_score": 76, "importance_score": 64}, {"source_item_ids": ["f023c33d5f8e8225"], "title_zh": "Google DeepMind 投资 A24，合作开发 AI 电影工具", "summary_zh": "TechCrunch 报道，Google DeepMind 宣布向电影公司 A24 投资 7500 万美元，并将与其合作开发面向电影制作的 AI 工具，DeepMind 称会从艺术家获得反馈。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/22/google-deepmind-bets-75m-on-ais-future-in-hollywood-with-a24-deal"}], "relevance_score": 66, "importance_score": 58}, {"source_item_ids": ["3f2a6117ead86326"], "title_zh": "手机系统把自然语言生成组件当成 AI 入口", "summary_zh": "爱范儿梳理称，Google、华为、苹果都在手机系统里推进自然语言生成小组件、快捷指令或浏览器扩展能力，让用户用描述生成系统级组件或工作流。", "sources": [{"name": "爱范儿", "url": "https://www.ifanr.com/1669508"}], "relevance_score": 70, "importance_score": 58}, {"source_item_ids": ["2779319c5495190d"], "title_zh": "北大团队用肌电腕带做 Physical AI 数据采集", "summary_zh": "36氪报道，雪梦未来获得龚虹嘉、陆奇和海外机构投资。团队用表面肌电信号、第一视角采集设备和 AI 解码模型，为具身智能和世界模型训练提供人类操控数据。", "sources": [{"name": "36氪", "url": "https://36kr.com/p/3865125383443463?f=rss"}], "relevance_score": 74, "importance_score": 60}], "discarded": [{"source_item_ids": ["f753d2611701715f"], "reason": "Oak 面向 agents 的版本控制工具有启发，但仍是 Show HN 项目，成熟度和影响面不足。", "relevance_score": 68, "importance_score": 58}, {"source_item_ids": ["0bb3e96f8617837f"], "reason": "昆仑行机器人融资信息较强，但融资叙事和估值信息占比高，本期已保留更具体的具身智能数据采集条目。", "relevance_score": 74, "importance_score": 66}, {"source_item_ids": ["a85708e0886a1b35"], "reason": "聚合晚报包含多个有用点，但可被更聚焦的单篇替代；其中 Reflection、Nvidia Rubin 等信息已在其他条目覆盖。", "relevance_score": 78, "importance_score": 68}, {"source_item_ids": ["60339fa51f9fe747"], "reason": "Codex 日志写盘问题对开发者相关，但属于具体工具故障，日报优先级低于 OpenAI 安全产品与漏洞修复计划。", "relevance_score": 70, "importance_score": 58}], "merged_sources": [{"source_item_ids": ["88b75cef83769816", "c0bfc8ee5e9ad564"], "reason": "同属 AI 芯片公司商业化和融资动态，可放在同一条头条候选里对照。"}, {"source_item_ids": ["b169271bf13b50ce", "e3a98cbb5c7c4389", "ba246d627f29e600"], "reason": "三条共同构成 AI 数据中心资源约束：设施内节水、设施外电力水耗、燃气电厂供能。"}, {"source_item_ids": ["ae15b112b9f6bdcc", "3a985468823590e8"], "reason": "同一 Tesla Autopilot 致命事故，一个来源提供 Tesla 回应，一个来源提供监管调查和警方信息。"}, {"source_item_ids": ["416004de0dc49352", "9b4a6b8f3f3e98df"], "reason": "两条都属于 OpenAI 将模型能力用于漏洞发现、补丁生成和网络防御。"}, {"source_item_ids": ["2d1ab8d865ad790e", "0285851d91c14cbd"], "reason": "同属 GLM-5.2 热点，一个讲本地运行，一个讲与 Opus 的实践对比。"}]};
